-- Per-session human-readable title generated by the orchestrator after the
-- first assistant turn completes (see Orchestrator.maybeGenerateTitle).
-- Lets clients render a session picker with short labels instead of opaque
-- UUIDs. NULL until the title-generation goroutine has produced one;
-- callers must treat NULL as "not yet generated" rather than as an error.
--
-- No backfill: maybeGenerateTitle only fires on Run, so sessions created
-- before this migration keep title = NULL indefinitely. Intentional —
-- pre-existing sessions have no live channel to push a title frame to,
-- and the persona-shaped first-message gate would re-cost the LLM call
-- for sessions the user may never revisit.
--
-- TEXT (not VARCHAR with explicit length) for SQLite/PostgreSQL portability
-- — matches the convention of 004/010 which also extend the sessions table.
ALTER TABLE sessions ADD COLUMN title TEXT;
